-- Guides table for manually-managed tool and practice content
CREATE TABLE IF NOT EXISTS guides (
  id bigint generated by default as identity primary key,
  slug text unique not null,
  title text not null,
  summary text not null,
  content text not null,
  type text not null check (type in ('tool', 'practice')),
  category text not null,
  icon text default 'Shield',
  url text,
  image_url text,
  is_active boolean default true,
  published_at timestamp with time zone default timezone('utc'::text, now()) not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

ALTER TABLE guides ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow public read on guides" ON guides FOR SELECT USING (is_active = true);

-- 10 Tool Guides
INSERT INTO guides (slug, title, summary, content, type, category, icon, url) VALUES
('password-managers', 'Password Managers: Bitwarden, 1Password & KeePass', 'Credential reuse remains the top initial access vector. A password manager eliminates it by generating and storing unique credentials per service.', E'## Why credentials fail without a vault\n\nMost breaches trace back to a reused or weak password. A password manager generates random, high-entropy credentials for every service, stores them in an encrypted vault, and autofills them so users never need to remember or type passwords.\n\n## Top options compared\n\n- **Bitwarden** - Open-source, self-hostable, free tier available. Best for teams wanting transparency and control.\n- **1Password** - Polished UI, travel mode, Watchtower breach alerts. Best for mixed enterprise/personal use.\n- **KeePass** - Offline-only, no cloud dependency. Best for air-gapped or high-security environments.\n\n## Deployment checklist\n\n- Enforce master password complexity (16+ chars or passphrase).\n- Enable TOTP or hardware key 2FA on the vault itself.\n- Set organization-wide policies: no browser-saved passwords, mandatory vault use.\n- Audit shared vaults quarterly and revoke stale access.\n- Train users on phishing-resistant autofill (only fills on correct domains).', 'tool', 'identity-security', 'Key', 'https://bitwarden.com'),

('vpn-services', 'VPN Services for Security Teams', 'VPNs encrypt traffic between endpoints and corporate resources, preventing interception on untrusted networks.', E'## When VPNs matter\n\nRemote access VPNs protect data in transit when employees connect from public Wi-Fi, hotels, or home networks. Site-to-site VPNs secure branch-to-datacenter links.\n\n## Leading options\n\n- **WireGuard** - Modern protocol, minimal attack surface, high throughput. Ideal for Linux-native teams.\n- **Tailscale** - WireGuard-based mesh VPN with zero-config NAT traversal. Best for distributed teams.\n- **OpenVPN** - Battle-tested, wide client support, flexible auth backends.\n\n## Hardening tips\n\n- Disable split tunneling unless explicitly required.\n- Rotate VPN certificates on a 90-day cycle.\n- Monitor for unusual connection patterns (off-hours, new geolocations).\n- Pair VPN access with device posture checks (patch level, EDR status).', 'tool', 'network-security', 'Shield', 'https://www.wireguard.com'),

('edr-platforms', 'Endpoint Detection & Response (EDR)', 'EDR platforms provide continuous endpoint monitoring, behavioral detection, and automated response to contain threats before lateral movement.', E'## What EDR does\n\nEDR agents run on endpoints (laptops, servers, containers) collecting telemetry: process execution, file changes, network connections, registry modifications. When anomalous behavior matches known attack patterns, the agent alerts and can isolate the endpoint automatically.\n\n## Market leaders\n\n- **CrowdStrike Falcon** - Cloud-native, lightweight agent, strong threat intelligence integration.\n- **Microsoft Defender for Endpoint** - Native Windows integration, included in E5 licensing.\n- **SentinelOne** - Autonomous response, rollback capability, strong Linux support.\n\n## Operational priorities\n\n- Deploy to 100% of endpoints including servers and CI/CD runners.\n- Tune detection policies to reduce false positives without creating blind spots.\n- Integrate with SIEM for correlated alerting.\n- Test response automation in staging before enabling auto-isolation in production.', 'tool', 'endpoint-security', 'Monitor', 'https://www.crowdstrike.com'),

('siem-platforms', 'SIEM Platforms for Security Operations', 'SIEM aggregates logs from across your infrastructure, correlates events, and surfaces actionable alerts for your SOC team.', E'## Core SIEM value\n\nA SIEM collects logs from firewalls, endpoints, identity providers, cloud services, and applications into a single searchable index. Correlation rules detect multi-stage attacks that no single log source would reveal.\n\n## Options by scale\n\n- **Splunk** - Industry standard, powerful SPL query language, extensive app ecosystem.\n- **Elastic Security** - Open-source core, scales horizontally, strong for cloud-native environments.\n- **Microsoft Sentinel** - Cloud-native SIEM built on Azure, deep Microsoft 365 integration.\n\n## Getting value from your SIEM\n\n- Start with high-value log sources: identity, endpoint, email, firewall.\n- Build detection rules around MITRE ATT&CK techniques relevant to your threat model.\n- Measure mean-time-to-detect (MTTD) and mean-time-to-respond (MTTR) monthly.\n- Prune noisy rules quarterly to keep analyst fatigue low.', 'tool', 'security-operations', 'BarChart3', 'https://www.splunk.com'),

('vulnerability-scanners', 'Vulnerability Scanners: Nessus, OpenVAS & Qualys', 'Regular vulnerability scanning identifies known weaknesses before attackers find them, giving teams a prioritized remediation queue.', E'## Why scanning matters\n\nAttackers scan your perimeter constantly. Vulnerability scanners do the same thing from the inside, identifying missing patches, misconfigurations, and exposed services before they become breach vectors.\n\n## Scanner comparison\n\n- **Nessus** - Deep plugin library, compliance scanning, agent-based or network scan modes.\n- **OpenVAS** - Open-source, community-maintained, good for budget-constrained teams.\n- **Qualys VMDR** - Cloud-hosted, asset discovery, risk-based prioritization.\n\n## Scanning best practices\n\n- Scan weekly at minimum, daily for internet-facing assets.\n- Prioritize by exploitability (EPSS score) not just CVSS severity.\n- Integrate scan results into ticketing (Jira, ServiceNow) with SLA deadlines.\n- Validate remediation with targeted re-scans, not just ticket closure.', 'tool', 'vulnerability-management', 'Search', 'https://www.tenable.com/products/nessus'),

('ai-security-tools', 'AI Security Assistants & Copilots', 'AI-powered security tools accelerate threat analysis, automate triage, and help analysts investigate incidents faster.', E'## AI in the SOC\n\nAI security copilots process alerts, correlate indicators, summarize incidents, and suggest response actions. They reduce analyst toil on repetitive tasks and surface insights that manual review would miss.\n\n## Notable tools\n\n- **Microsoft Security Copilot** - GPT-4 powered, integrates across Microsoft security stack.\n- **Google Threat Intelligence (Gemini)** - Malware analysis, threat report summarization.\n- **CrowdStrike Charlotte AI** - Natural language querying of endpoint telemetry.\n\n## Responsible deployment\n\n- Never auto-execute AI-suggested remediations without human review.\n- Validate AI findings against ground truth data before acting.\n- Monitor for hallucinated IOCs or false correlations.\n- Use AI to augment junior analysts, not replace senior judgment.', 'tool', 'ai-security', 'Bot', NULL),

('network-monitoring', 'Network Monitoring & Traffic Analysis', 'Network monitoring tools detect anomalous traffic patterns, lateral movement, and data exfiltration by analyzing packet flows and metadata.', E'## Why network visibility matters\n\nEndpoint agents can be bypassed. Network monitoring provides an independent detection layer by analyzing traffic flows, DNS queries, and protocol behavior across your infrastructure.\n\n## Key tools\n\n- **Zeek (Bro)** - Open-source network analysis framework, generates rich connection logs.\n- **Suricata** - IDS/IPS with multi-threaded packet processing and Lua scripting.\n- **Darktrace** - AI-driven anomaly detection, self-learning baseline of normal behavior.\n\n## Deployment guidance\n\n- Mirror traffic from core switches and internet egress points.\n- Monitor DNS queries for DGA domains and tunneling.\n- Alert on unusual data volumes leaving the network (potential exfiltration).\n- Retain network metadata for at least 90 days for incident investigation.', 'tool', 'network-security', 'Wifi', NULL),

('container-security', 'Container Security: Trivy, Snyk & Falco', 'Containers ship vulnerabilities if images are not scanned. Runtime protection catches exploitation attempts that static scanning misses.', E'## Container threat model\n\nContainer images inherit vulnerabilities from base images and dependencies. Misconfigured orchestrators expose management APIs. Runtime attacks escalate privileges from container to host.\n\n## Toolchain\n\n- **Trivy** - Fast, comprehensive image scanner. Covers OS packages, language deps, IaC misconfigs.\n- **Snyk Container** - Developer-friendly scanning integrated into CI/CD pipelines.\n- **Falco** - Runtime security monitoring using kernel-level syscall analysis.\n\n## Security pipeline\n\n- Scan images in CI before push to registry (block critical/high CVEs).\n- Use minimal base images (distroless, Alpine) to reduce attack surface.\n- Enforce read-only root filesystems and drop unnecessary Linux capabilities.\n- Monitor runtime with Falco for unexpected process execution or network connections.', 'tool', 'cloud-security', 'Container', 'https://aquasecurity.github.io/trivy'),

('threat-intel-platforms', 'Threat Intelligence Platforms', 'Threat intelligence platforms aggregate IOCs, map adversary TTPs, and enrich alerts with context to prioritize what matters.', E'## What threat intel platforms do\n\nThey collect indicators of compromise (IPs, domains, hashes, URLs) from open-source feeds, commercial providers, and internal sensors, then correlate them with your environment to identify active threats.\n\n## Platform options\n\n- **MISP** - Open-source, community-driven, strong sharing capabilities between organizations.\n- **Recorded Future** - AI-powered intelligence with dark web monitoring and geopolitical context.\n- **Anomali ThreatStream** - Aggregates 100+ feeds, integrates with SIEM and SOAR platforms.\n\n## Making intel actionable\n\n- Feed curated IOCs directly into firewall and EDR blocklists.\n- Map incoming threats to MITRE ATT&CK techniques for detection gap analysis.\n- Share intelligence with ISACs and trusted peers for collective defense.\n- Measure intel effectiveness: how many alerts were enriched, how many threats were blocked proactively.', 'tool', 'threat-intel', 'Eye', 'https://www.misp-project.org'),

('secrets-management', 'Secrets Management: Vault, AWS Secrets Manager & Doppler', 'Hardcoded secrets in code repositories are a top breach cause. Secrets management tools eliminate static credentials from your codebase.', E'## The secrets problem\n\nAPI keys, database passwords, and TLS certificates embedded in source code, environment variables, or config files get exposed through git history, log files, and error messages.\n\n## Solutions\n\n- **HashiCorp Vault** - Dynamic secrets, encryption-as-a-service, audit logging. Self-hosted or HCP cloud.\n- **AWS Secrets Manager** - Native AWS integration, automatic rotation for RDS and Redshift credentials.\n- **Doppler** - Developer-friendly secrets sync across environments and CI/CD pipelines.\n\n## Implementation steps\n\n- Scan existing repos for leaked secrets using tools like TruffleHog or GitLeaks.\n- Migrate all hardcoded credentials to your secrets manager.\n- Enable automatic credential rotation (90-day maximum lifetime).\n- Audit access logs monthly: who accessed which secrets and when.\n- Integrate secrets injection into CI/CD so developers never see production credentials.', 'tool', 'identity-security', 'Lock', 'https://www.vaultproject.io');

-- 10 Practice Guides
INSERT INTO guides (slug, title, summary, content, type, category, icon) VALUES
('zero-trust-architecture', 'Zero Trust Architecture Implementation', 'Zero Trust eliminates implicit trust by verifying every access request regardless of network location, user identity, or device status.', E'## Core principle\n\nNever trust, always verify. Every request to access resources must be authenticated, authorized, and encrypted, whether it originates from inside or outside the network perimeter.\n\n## Implementation pillars\n\n- **Identity verification** - MFA everywhere, conditional access policies, just-in-time privilege elevation.\n- **Device trust** - Endpoint health checks before granting access (patch level, EDR status, encryption).\n- **Micro-segmentation** - Limit lateral movement by segmenting networks at the workload level.\n- **Least privilege** - Grant minimum necessary permissions, review quarterly.\n\n## Getting started\n\n- Map your critical assets and data flows.\n- Implement MFA on all identity providers (Entra ID, Okta, Google Workspace).\n- Deploy conditional access: block unmanaged devices from sensitive resources.\n- Monitor and log all access decisions for forensic analysis.\n- Measure progress against NIST SP 800-207 Zero Trust maturity model.', 'practice', 'identity-security', 'ShieldCheck'),

('incident-response-planning', 'Incident Response Planning & Playbooks', 'A tested incident response plan reduces breach impact by 50%. Without one, teams waste critical hours figuring out who does what.', E'## Why plans fail\n\nMost IR plans sit in a shared drive, unread and untested. When a breach hits, teams scramble. Effective IR requires rehearsed playbooks, clear escalation paths, and pre-authorized response actions.\n\n## Plan structure\n\n- **Preparation** - Tool readiness, contact lists, legal/PR coordination, evidence preservation procedures.\n- **Detection & Analysis** - Triage criteria, severity classification, initial scoping checklist.\n- **Containment** - Short-term (isolate), long-term (patch/rebuild), evidence collection.\n- **Eradication & Recovery** - Root cause removal, system restoration, validation testing.\n- **Post-Incident** - Lessons learned within 72 hours, control improvements, metrics update.\n\n## Tabletop exercises\n\n- Run quarterly tabletop exercises with realistic scenarios.\n- Include legal, communications, and executive leadership.\n- Time each phase and identify bottlenecks.\n- Update playbooks based on exercise findings within 2 weeks.', 'practice', 'security-operations', 'FileText'),

('security-awareness-training', 'Security Awareness Training That Works', 'Human error causes 82% of breaches. Effective security training changes behavior, not just checkbox compliance.', E'## Beyond compliance checkboxes\n\nAnnual slide decks do not change behavior. Effective training uses real-world simulations, just-in-time coaching, and measurable behavior change metrics.\n\n## What works\n\n- **Phishing simulations** - Monthly campaigns with escalating difficulty. Track click rates, report rates, and repeat offenders.\n- **Just-in-time training** - When a user clicks a simulated phish, deliver a 2-minute micro-lesson immediately.\n- **Role-based content** - Developers get secure coding training, finance gets BEC awareness, executives get whaling scenarios.\n\n## Metrics that matter\n\n- Phishing click rate trend (target: under 5%).\n- Report rate (users who flag suspicious emails).\n- Time-to-report (how quickly users escalate).\n- Repeat offender rate (users who fail multiple simulations).\n\n## Program tips\n\n- Reward reporters, do not shame clickers.\n- Vary simulation types: email, SMS, voice, QR codes.\n- Brief leadership on metrics quarterly.', 'practice', 'security-operations', 'Users'),

('patch-management', 'Patch Management Best Practices', 'Unpatched systems remain the most exploited attack vector. A structured patch management program closes vulnerabilities before adversaries find them.', E'## The patching gap\n\nThe average time from CVE disclosure to exploitation is 15 days. Most organizations take 60+ days to patch. This gap is where breaches happen.\n\n## Patch management framework\n\n- **Inventory** - Maintain a real-time asset inventory (you cannot patch what you do not know about).\n- **Prioritize** - Use EPSS (Exploit Prediction Scoring System) alongside CVSS to rank patches by actual risk.\n- **Test** - Stage patches in a representative test environment before production deployment.\n- **Deploy** - Use automated deployment tools (WSUS, SCCM, Ansible) with rollback capability.\n- **Verify** - Confirm patches applied successfully via vulnerability re-scan.\n\n## SLA targets\n\n- Critical (actively exploited): 24-48 hours.\n- High severity: 7 days.\n- Medium severity: 30 days.\n- Low severity: 90 days.\n- Track compliance rates per SLA tier monthly.', 'practice', 'vulnerability-management', 'RefreshCw'),

('data-encryption', 'Data Encryption Standards & Implementation', 'Encryption protects data confidentiality at rest, in transit, and in use. Proper key management is the difference between real protection and security theater.', E'## Encryption layers\n\n- **In transit** - TLS 1.3 for all external and internal communications. Deprecate TLS 1.0/1.1.\n- **At rest** - AES-256 for disk encryption, database encryption (TDE), and object storage.\n- **In use** - Confidential computing for sensitive workloads (AMD SEV, Intel SGX, AWS Nitro Enclaves).\n\n## Key management\n\n- Use a dedicated KMS (AWS KMS, Azure Key Vault, HashiCorp Vault).\n- Separate encryption keys from encrypted data.\n- Rotate keys annually or on suspected compromise.\n- Implement envelope encryption: data keys encrypted by master keys.\n\n## Common mistakes\n\n- Using ECB mode (use GCM or CBC with HMAC instead).\n- Storing keys alongside encrypted data.\n- Not encrypting database backups.\n- Forgetting to encrypt log files containing sensitive data.', 'practice', 'data-security', 'Lock'),

('access-control-iam', 'Access Control & Identity Management', 'Identity is the new perimeter. Proper IAM ensures only the right people access the right resources at the right time.', E'## IAM fundamentals\n\nIdentity and Access Management controls who can access what, under which conditions, and for how long. It is the foundation of every security architecture.\n\n## Core practices\n\n- **Multi-factor authentication** - Enforce on all accounts. Prefer FIDO2/WebAuthn over SMS OTP.\n- **Least privilege** - Start with zero access, grant only what is needed, review quarterly.\n- **Just-in-time access** - Elevate privileges temporarily (PIM/PAM) rather than persistent admin rights.\n- **SSO integration** - Centralize authentication through SAML/OIDC to reduce credential sprawl.\n\n## Operational checklist\n\n- Audit privileged accounts monthly.\n- Remove access within 24 hours of employee departure.\n- Monitor for impossible travel (login from two countries in one hour).\n- Implement break-glass procedures for emergency access with full audit trail.', 'practice', 'identity-security', 'UserCheck'),

('log-management', 'Log Management & SIEM Configuration', 'Without centralized logging, incidents go undetected. Proper log management is the backbone of threat detection and forensic investigation.', E'## What to log\n\n- **Authentication events** - Successful and failed logins, MFA challenges, password resets.\n- **Authorization changes** - Permission grants, role modifications, group membership changes.\n- **Network events** - Firewall logs, DNS queries, proxy access logs.\n- **Endpoint events** - Process creation, file modifications, registry changes.\n\n## Log architecture\n\n- Centralize logs in a SIEM or log aggregation platform.\n- Normalize log formats using a common schema (ECS, OCSF).\n- Set retention policies: 90 days hot, 1 year warm, 7 years cold for compliance.\n- Protect log integrity with write-once storage or hash chains.\n\n## Detection engineering\n\n- Build detections around MITRE ATT&CK techniques.\n- Start with high-confidence, low-noise rules before expanding coverage.\n- Measure detection coverage against your top 20 threat scenarios.\n- Review and tune alert rules monthly to combat alert fatigue.', 'practice', 'security-operations', 'BarChart3'),

('backup-disaster-recovery', 'Backup & Disaster Recovery Planning', 'Ransomware makes backups a survival tool, not just a compliance checkbox. Untested backups are not backups.', E'## The 3-2-1-1 rule\n\nMaintain 3 copies of data, on 2 different media types, with 1 offsite copy, and 1 immutable copy that cannot be encrypted or deleted by ransomware.\n\n## Backup strategy\n\n- **Full backups** - Weekly for critical systems.\n- **Incremental backups** - Daily for changed data.\n- **Application-aware snapshots** - For databases and stateful workloads.\n- **Configuration backups** - Network devices, cloud infrastructure (IaC state files).\n\n## Testing requirements\n\n- Test full restoration monthly for critical systems.\n- Measure RTO (Recovery Time Objective) and RPO (Recovery Point Objective) against business requirements.\n- Simulate ransomware scenarios: can you recover without paying?\n- Document and rehearse the recovery process so it works under pressure.\n\n## Anti-ransomware measures\n\n- Enable immutable backups (WORM storage, S3 Object Lock).\n- Air-gap at least one backup copy from production networks.\n- Monitor backup job success rates daily.', 'practice', 'security-operations', 'HardDrive'),

('supply-chain-security', 'Software Supply Chain Security', 'SolarWinds, Log4j, and xz-utils proved that your software supply chain is an attack surface. Third-party code needs the same scrutiny as your own.', E'## Supply chain attack surface\n\nModern applications use hundreds of open-source dependencies. Each one is a potential entry point for malicious code, whether through compromised maintainer accounts, typosquatting, or backdoored build pipelines.\n\n## Defense measures\n\n- **SBOM generation** - Create Software Bills of Materials for every release using tools like Syft or CycloneDX.\n- **Dependency scanning** - Scan dependencies for known CVEs in CI/CD (Dependabot, Renovate, Snyk).\n- **Lockfile enforcement** - Pin dependency versions and verify checksums.\n- **Artifact signing** - Sign container images and releases with Sigstore/Cosign.\n\n## Vendor assessment\n\n- Evaluate third-party security posture before onboarding (SOC 2, penetration test reports).\n- Monitor vendor breach disclosures and respond within 24 hours.\n- Maintain a vendor inventory with data access classification.\n- Include supply chain scenarios in incident response tabletop exercises.', 'practice', 'vulnerability-management', 'GitBranch'),

('cloud-security-posture', 'Cloud Security Posture Management', 'Cloud misconfigurations cause more breaches than sophisticated attacks. CSPM tools continuously audit your cloud environment against security benchmarks.', E'## Why cloud misconfigs happen\n\nCloud platforms offer thousands of configuration options. Default settings prioritize convenience over security. Infrastructure-as-code drift introduces misconfigs silently.\n\n## CSPM essentials\n\n- **Continuous compliance** - Scan cloud resources against CIS Benchmarks, SOC 2, and PCI-DSS controls.\n- **Drift detection** - Alert when running infrastructure diverges from approved IaC templates.\n- **Identity analysis** - Find overprivileged IAM roles, unused permissions, and cross-account trust chains.\n\n## Tool options\n\n- **Wiz** - Agentless cloud security, risk-based prioritization, attack path analysis.\n- **Prowler** - Open-source AWS/Azure/GCP security auditing.\n- **Prisma Cloud** - Full CNAPP: CSPM, CWPP, CIEM, and code security.\n\n## Quick wins\n\n- Block public S3 buckets and storage accounts at the organization level.\n- Enable CloudTrail/Activity Log in all regions and accounts.\n- Require MFA for root/global admin accounts.\n- Review security group rules monthly for overly permissive ingress.', 'practice', 'cloud-security', 'Cloud');
